Original message
we need to calculate the credit attributes per each account using these formulas. below the image in xcrm what possible values we need to save. all these need to be calculated on salesorder CRUD invoice  CRUD and payments:
//sample workin for sinle invoice-Open invoie only
foreach ($invlineModels as $key => $invlineModel) {

 $inv=($invlineModel->INVLINE_CODE_)?$invlineModel->oldinvoice:$invlineModel->newinvoice;
 if ($tax_rate == '') {
    $tax_rate = 0;
 }
 $Tax=  ($tax_rate/100) * ($inv->SUM_+$inv->FREIGHT_+$inv->C1X_MISC_CHARGES_+$inv->C1X_BANK_CHARGES_);
 $amount = ($Tax+$inv->SUM_+$inv->RE_STOCKING_FEE_+$inv->FREIGHT_+$inv->C1X_MISC_CHARGES_);
 $amount=(($amount - $totalPayed)>0)?$amount - $totalPayed:0;
 if ($total_days_past < 1)
  $total_days_past = $total_days_past * -1;
 if ($total_days_past < 30)
 {
  $days_0 = $days_0 + $amount;
 } else if ($total_days_past >= 30 && $total_days_past < 60) {
  $days_30 = $days_30 + $amount;
 } else if ($total_days_past >= 60 && $total_days_past < 90) {
  $days_60 = $days_60 + $amount;
 } else if ($total_days_past >= 90 && $total_days_past < 120) {
  $days_90 = $days_90 + $amount;
 } else if ($total_days_past >= 120) {
  $days_120_plus = $days_120_plus + $amount;
 }
 $invBalance = $days_0 + $days_30 + $days_60 + $days_90 + $days_120_plus;


}
----Save data into cm offie fields 
$cmoffice_data->CURRENT_ = $invBalance;
$cmoffice_data->DAYS30_ = $days_30;
$cmoffice_data->DAYS60_ = $days_60;
$cmoffice_data->DAYS90_ = $days_90;
$cmoffice_data->DAYS120_ = $days_120_plus;


-----So working for open and posted lines calculation only
 foreach ($solineModels as $key => $solineModel) {
 $soModel=($solineModel->SOLINE_CODE_)?$solineModel->oldso:$solineModel->newso;
 $qty=$solineModel->QTY_;
 if($qty == $QtyShipped) continue;
 if($QtyShipped>0){
  //remove shipped qty from calculation as it will be calculated in pending invoices
  $qty=$solineModel->QTY_ - $QtyShipped;
 }
 $linevalue=$qty*$solineModel->PRICE_;

 $lineTax=  ($tax_rate/100) * $linevalue;
 $lineamount=$linevalue+$lineTax;
 /* * *Convert SUM Into Parent Account  Sales FUND CODE Currency * */
 $currentSO = $soModel->FREIGHT_+$soModel->C1X_MISC_CHARGES_+$soModel->C1X_BANK_CHARGES_;
 $so_charges_tax = ($tax_rate/100)*($soModel->FREIGHT_+$soModel->C1X_MISC_CHARGES_+$soModel->C1X_BANK_CHARGES_);
 $currentSO+=$so_charges_tax;
 $soBalance += $currentSO;
}
----Save data into cm offie fields 
$cmoffice_data->C1X_PEND_SO_AMOUNT_ = $soBalance;
